// ---------------------------------------------------------------------------
// Colors per transition type
// ---------------------------------------------------------------------------
const COLORS = {
  enter:    '#007755',
  exit:     '#cc3300',
  move:     '#0055bb',
  expand:   '#7700cc',
  feedback: '#bb5500',
};

// ---------------------------------------------------------------------------
// Animation builders per transition type
// All use Web Animations API; effects match the semantic description
// ---------------------------------------------------------------------------
function animateEnter(box, duration, easing) {
  // Fade + slide in from left
  box.style.opacity = '0';
  box.style.transform = 'translateX(-40px)';
  box.style.width = '60px';
  box.style.height = '60px';
  box.style.position = 'absolute';
  box.style.left = '0';
  box.style.top = '0';

  return box.animate(
    [
      { opacity: 0, transform: 'translateX(-40px)' },
      { opacity: 1, transform: 'translateX(0px)' },
    ],
    { duration, easing, fill: 'forwards' }
  );
}

function animateExit(box, duration, easing) {
  // Fade + slide out to right
  box.style.opacity = '1';
  box.style.transform = 'translateX(0px)';
  box.style.width = '60px';
  box.style.height = '60px';
  box.style.position = 'absolute';
  box.style.left = '0';
  box.style.top = '0';

  return box.animate(
    [
      { opacity: 1, transform: 'translateX(0px)' },
      { opacity: 0, transform: 'translateX(60px)' },
    ],
    { duration, easing, fill: 'forwards' }
  );
}

function animateMove(box, stageW, duration, easing) {
  // Position change within stage
  const travel = stageW - 60;
  box.style.transform = 'translateX(0px)';
  box.style.width = '60px';
  box.style.height = '60px';
  box.style.position = 'absolute';
  box.style.left = '0';
  box.style.top = '0';

  return box.animate(
    [
      { transform: 'translateX(0px)' },
      { transform: `translateX(${travel}px)` },
      { transform: 'translateX(0px)' },
    ],
    { duration: duration * 2, easing, fill: 'forwards' }
  );
}

function animateExpand(box, duration, easing) {
  // Height expansion (accordion)
  box.style.height = '20px';
  box.style.width = '120px';
  box.style.position = 'absolute';
  box.style.left = '0';
  box.style.bottom = '0';
  box.style.borderRadius = '5px 5px 0 0';

  return box.animate(
    [
      { height: '20px' },
      { height: '60px' },
      { height: '20px' },
    ],
    { duration: duration * 3, easing, fill: 'forwards' }
  );
}

function animateFeedback(box, duration, easing) {
  // Scale pulse — press feedback
  box.style.transform = 'scale(1)';
  box.style.width = '60px';
  box.style.height = '60px';
  box.style.position = 'absolute';
  box.style.left = '30px';
  box.style.top = '0';

  return box.animate(
    [
      { transform: 'scale(1)' },
      { transform: 'scale(0.88)' },
      { transform: 'scale(1)' },
    ],
    { duration: duration * 2, easing, fill: 'forwards' }
  );
}

// ---------------------------------------------------------------------------
// Render helper
// ---------------------------------------------------------------------------
function buildRow(name, transition) {
  const { duration, easing, description } = transition;
  const bezierCSS = cubicBezierCSS(easing);
  const color = COLORS[name] || '#333';
  const durationMs = parseInt(duration, 10);
  const safeId = `comp_${name}`;

  // Short label showing what the animation does
  const effectLabel = {
    enter:    'fade + slide in',
    exit:     'fade + slide out',
    move:     'position change',
    expand:   'height expand',
    feedback: 'scale pulse',
  }[name] || '';

  return `
    <div class="row" onclick="triggerComposite('${safeId}', '${name}', '${bezierCSS}', ${durationMs})">
      <div>
        <div class="token-name">motion.transition.${name}</div>
        <div style="font-size: 11px; color: #aaa; margin-top: 4px;">${effectLabel}</div>
      </div>
      <div class="resolved">
        <div><span class="resolved-key">duration </span>${duration}</div>
        <div><span class="resolved-key">easing   </span>${bezierCSS}</div>
        <div><span class="resolved-key">delay    </span>0ms</div>
      </div>
      <div class="token-desc">${description}</div>
      <div class="stage">
        <div class="ref-box" id="${safeId}" style="background: ${color}; width: 60px; height: 60px; position: absolute; left: 0; top: 0;">
          ${name}
        </div>
      </div>
    </div>
  `;
}

// ---------------------------------------------------------------------------
// Story: All composite transitions
// ---------------------------------------------------------------------------
export const AllTransitions = {
  name: 'Composite transitions',
  render: () => {
    const rows = Object.entries(TRANSITIONS)
      .map(([name, t]) => buildRow(name, t))
      .join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Motion / Composites</div>
        <div class="page-subtitle">Semantic composite transitions</div>
        <div class="page-description">
          Five named transitions, each composing a duration and easing into a semantic pattern.
          Click any row to trigger the animation appropriate to that transition type.
          Each animation matches its semantic description — not a generic slide.
        </div>
        <div class="header-row">
          <div>Token</div>
          <div>Resolved values</div>
          <div>Description</div>
          <div>Preview</div>
        </div>
        ${rows}
      </div>
    `;

    el.ownerDocument.defaultView.triggerComposite = (id, name, bezier, durationMs) => {
      const box = el.querySelector(`#${id}`);
      if (!box || box._animating) return;
      box._animating = true;

      const stage = box.parentElement;
      const stageW = stage.offsetWidth || 120;
      let anim;

      switch (name) {
        case 'enter':
          anim = animateEnter(box, durationMs, bezier);
          break;
        case 'exit':
          anim = animateExit(box, durationMs, bezier);
          break;
        case 'move':
          anim = animateMove(box, stageW, durationMs, bezier);
          break;
        case 'expand':
          anim = animateExpand(box, durationMs, bezier);
          break;
        case 'feedback':
          anim = animateFeedback(box, durationMs, bezier);
          break;
      }

      if (anim) {
        anim.onfinish = () => {
          box._animating = false;
        };
      } else {
        box._animating = false;
      }
    };

    return el;
  },
};

